import { useEffect,useState } from "react";
import { useContent } from "../context/ContentContext"
import { useNavigate } from "react-router-dom";
import { isNotEmpty } from "../utils/validations";
import { useAuth } from "../context/AuthContext"


export default function AddContent() {
  const {addContent} = useContent();
  const navigate = useNavigate();
  const {user} = useAuth();

  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [category, setCategory] = useState('Misc');
  const [error, setError]  = useState('');
  const [showPreview, setShowPreview] = useState(false);

  useEffect(() => {
    const draft = localStorage.getItem('contentDraft');
    if(draft) {
      try{
        const {title, body, category} = JSON.parse(draft);
        setTitle(title || '');
        setBody(body || '');
        setCategory(category || 'Misc');
      }catch(error){
        console.error('Error in parsing draft', error)
      }
    }
  }, []);

  const handleSubmit = (e) => {
    e.preventDefault();
    if(!isNotEmpty(title) || !isNotEmpty(body)) {
      setError('Please fill title and body for article');
      return;
    }
    const newContent = {
      id: Date.now(),
      title,
      body,
      category,
      date: new Date().toISOString(),
      author: user.mobile
    }
    addContent(newContent);
    setTitle('');
    setBody('');
    setCategory('Misc');
    setError('')
    localStorage.removeItem('contentDraft');
    navigate('/view')
  }



  return (
    <div className="panel">
      <h2>Add Content</h2>
      <form onSubmit={handleSubmit} className="content-form">
        <div className="form-group">
          <label htmlFor="title">Title:</label>
          <input 
            id="title" 
            type="text" 
            placeholder="Enter title" 
            value={title} 
            onChange={(e) => setTitle(e.target.value)} 
          />
        </div>
        <div className="form-group">
          <label htmlFor="body">Content:</label>
          <textarea 
            id="body" 
            placeholder="Enter content" 
            value={body} 
            onChange={(e) => setBody(e.target.value)} 
          />
        </div>
        <div className="form-group">
          <label htmlFor="category">Category:</label>
          <select 
            id="category" 
            value={category} 
            onChange={(e) => setCategory(e.target.value)}
          >
            <option value="News">News</option>
            <option value="Blog">Blog</option>
            <option value="Tutorial">Tutorial</option>
            <option value="Misc">Misc</option>
          </select>
        </div>
        <div className="form-group">
          <label>
            <input 
              type="checkbox" 
              checked={showPreview} 
              onChange={() => setShowPreview((prev => !prev))}
            />
            Show preview
          </label>
        </div>
        {error && <div className="error">{error}</div>}
        <button type="submit" className="btn">
          Add content
        </button>
      </form>
      {showPreview && (
        <div className="preview">
          <h3>Preview</h3>
          <h4>{title || 'Title'}</h4>
          <p>{body || 'Content preview'}</p>
          <small>Category: {category}</small>
        </div>
      )}
    </div>
  )
}
